mapper.sql:
r.tenant_id = #{tenantId}

    and (lower(r.rule_code) like concat('%', lower(#{keyword}), '%')
    or lower(r.rule_name) like concat('%', lower(#{keyword}), '%')
    or lower(r.object_code) like concat('%', lower(#{keyword}), '%')
    or lower(r.object_name) like concat('%', lower(#{keyword}), '%'))


    and r.metric_definition_id = #{metricDefinitionId}


    and r.scope_type = #{scopeType}


    and r.object_type = #{objectType}


    and r.object_id = #{objectId}


    and r.enabled = #{enabled}

mapper.select:
select 
from 
where r.tenant_id = #{tenantId} and r.id = #{id}

select 
from 
where r.tenant_id = #{tenantId} and r.rule_code = #{ruleCode}

select r.*, m.metric_code, m.metric_name
from fp_threshold_rule r
left join fp_metric_definition m on m.tenant_id = r.tenant_id and m.id = r.metric_definition_id
where r.tenant_id = #{tenantId}
  and r.metric_definition_id = #{metricDefinitionId}
  and r.scope_type = 'RESOURCE'
  and r.object_type = #{objectType}
  and r.object_id = #{objectId}
  and r.enabled = true
order by r.updated_at desc
